class Solution {
public:
    string smallestNumber(string pattern) {
        string num = "123456789";
        string res = "";
        for (char c : pattern) {
            if (c == 'I') {
                res += num[0];
                num.erase(num.begin());
            } else {
                for (int i = num.size() - 1; i >= 0; --i) {
                    if (res.empty() || res.back() > num[i]) {
                        res += num[i];
                        num.erase(num.begin() + i);
                        break;
                    }
                }
            }
        }
        res += num;
        return res;
    }
};
